import chess

def evaluate_position(board):
    """
    Evaluates a chess position and returns a numerical score.
    Positive score indicates white advantage, negative score indicates black advantage.
    """

    piece_values = {
        chess.PAWN: 1,
        chess.KNIGHT: 3,
        chess.BISHOP: 3,
        chess.ROOK: 5,
        chess.QUEEN: 9,
        chess.KING: 0  # King value is not directly used, but considered in checkmate/stalemate
    }

    score = 0

    # Material balance
    for piece_type in piece_values:
        score += (len(board.pieces(piece_type, chess.WHITE)) - len(board.pieces(piece_type, chess.BLACK))) * piece_values[piece_type]

    # Controlled squares (simplified - counts attacked squares)
    white_controlled_squares = 0
    black_controlled_squares = 0
    for square in chess.SQUARES:
        if board.is_attacked_by(chess.WHITE, square):
            white_controlled_squares += 0.1  # Slightly less than a pawn
        if board.is_attacked_by(chess.BLACK, square):
            black_controlled_squares += 0.1

    score += white_controlled_squares - black_controlled_squares

    # Mobility (number of legal moves)
    legal_moves = list(board.legal_moves)
    white_mobility = 0
    black_mobility = 0
    for move in legal_moves:
        if board.turn == chess.WHITE:
            white_mobility += 0.05
        else:
            black_mobility += 0.05

    score += white_mobility - black_mobility

    # Checkmate/Stalemate considerations
    if board.is_checkmate():
        if board.turn == chess.WHITE:
            score = -1000  # Black wins
        else:
            score = 1000   # White wins
    elif board.is_stalemate() or board.is_insufficient_material() or board.is_seventyfive_moves() or board.is_fivefold_repetition() or board.is_repetition():
        score = 0  # Draw

    return score

